import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"📊 功率離散元件產業總覽","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散元件_產業總覽.md","filePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散元件_產業總覽.md"}'),i={name:"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散元件_產業總覽.md"};function s(r,t,d,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="📊-功率離散元件產業總覽" tabindex="-1">📊 功率離散元件產業總覽 <a class="header-anchor" href="#📊-功率離散元件產業總覽" aria-label="Permalink to &quot;📊 功率離散元件產業總覽&quot;">​</a></h1><p><strong>更新日期：</strong> 2026-05-12 <strong>研究範圍：</strong> MOSFET / SiC 功率離散元件全球市場與台廠全景</p><hr><h2 id="_1-產業定義" tabindex="-1">1. 產業定義 <a class="header-anchor" href="#_1-產業定義" aria-label="Permalink to &quot;1. 產業定義&quot;">​</a></h2><h3 id="功率半導體-vs-邏輯半導體" tabindex="-1">功率半導體 vs 邏輯半導體 <a class="header-anchor" href="#功率半導體-vs-邏輯半導體" aria-label="Permalink to &quot;功率半導體 vs 邏輯半導體&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">功率離散元件</th><th style="text-align:left;">邏輯/記憶體 IC</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>功能</strong></td><td style="text-align:left;">電源轉換、開關控制、保護</td><td style="text-align:left;">運算、儲存、訊號處理</td></tr><tr><td style="text-align:left;"><strong>電壓/電流</strong></td><td style="text-align:left;">高電壓（V）、大電流（A）</td><td style="text-align:left;">低電壓（mV-V）、小電流</td></tr><tr><td style="text-align:left;"><strong>製程節點</strong></td><td style="text-align:left;">成熟製程（0.18μm-3μm）</td><td style="text-align:left;">先進製程（5nm-7nm）</td></tr><tr><td style="text-align:left;"><strong>封裝</strong></td><td style="text-align:left;">離散封裝（TO、SMD、DPAK）</td><td style="text-align:left;">IC 封裝（BGA、QFN）</td></tr><tr><td style="text-align:left;"><strong>代表元件</strong></td><td style="text-align:left;">MOSFET、IGBT、SiC、GaN</td><td style="text-align:left;">CPU、GPU、DRAM</td></tr></tbody></table><p><strong>功率離散元件的角色：</strong> 電源轉換（AC/DC、DC/DC）、馬達控制、開關保護、電壓調節。與 IC 的區別在於「離散」代表單一功能元件，而 IC 是整合電路（多元件整合在一顆晶片上）。</p><hr><h2 id="_2-全球市場規模" tabindex="-1">2. 全球市場規模 <a class="header-anchor" href="#_2-全球市場規模" aria-label="Permalink to &quot;2. 全球市場規模&quot;">​</a></h2><h3 id="功率半導體整體市場-2025-2035" tabindex="-1">功率半導體整體市場（2025-2035） <a class="header-anchor" href="#功率半導體整體市場-2025-2035" aria-label="Permalink to &quot;功率半導體整體市場（2025-2035）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">市場規模</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">2025</td><td style="text-align:left;">~$557 億 USD</td><td style="text-align:left;">DataMintelligence, IMARC, GM Insights</td></tr><tr><td style="text-align:left;">2026</td><td style="text-align:left;">~$574-588 億 USD</td><td style="text-align:left;">DataMintelligence, IMARC (CAGR 3.0-5.8%)</td></tr><tr><td style="text-align:left;">2030 預估</td><td style="text-align:left;">~$700-850 億 USD</td><td style="text-align:left;">各機構預測區間</td></tr></tbody></table><h3 id="mosfet-市場規模-2025-2031" tabindex="-1">MOSFET 市場規模（2025-2031） <a class="header-anchor" href="#mosfet-市場規模-2025-2031" aria-label="Permalink to &quot;MOSFET 市場規模（2025-2031）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">市場規模</th><th style="text-align:left;">CAGR</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">2025</td><td style="text-align:left;">~$74.5-289 億 USD（依定義不同）</td><td style="text-align:left;">4.4-7.1%</td><td style="text-align:left;">Mordor, Precedence, BusinessResearch</td></tr><tr><td style="text-align:left;">2026</td><td style="text-align:left;">~$78.2-304 億 USD</td><td style="text-align:left;">—</td><td style="text-align:left;">同上</td></tr><tr><td style="text-align:left;">2031 預估</td><td style="text-align:left;">~$121 億 USD（保守定義）</td><td style="text-align:left;">6.3%</td><td style="text-align:left;">GII, Fortune Business Insights</td></tr></tbody></table><h3 id="sic-功率裝置市場-2025-2035" tabindex="-1">SiC 功率裝置市場（2025-2035） <a class="header-anchor" href="#sic-功率裝置市場-2025-2035" aria-label="Permalink to &quot;SiC 功率裝置市場（2025-2035）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">市場規模</th><th style="text-align:left;">CAGR</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">2025</td><td style="text-align:left;">~$21-40 億 USD（含 SiC MOSFET+SBD）</td><td style="text-align:left;">24.7-35%</td><td style="text-align:left;">Mordor, DataMintelligence, InsightAce</td></tr><tr><td style="text-align:left;">2026</td><td style="text-align:left;">~$34-53 億 USD（SiC 功率元件總計）</td><td style="text-align:left;">—</td><td style="text-align:left;">各機構加總</td></tr><tr><td style="text-align:left;">2035 預估</td><td style="text-align:left;">~$242-521 億 USD</td><td style="text-align:left;">15.9-30.4%</td><td style="text-align:left;">Mordor, DataMintelligence</td></tr></tbody></table><blockquote><p><strong>關鍵數字：</strong> SiC 功率元件 CAGR 約 25-35%，遠超整體功率半導體的 3-6%。</p></blockquote><hr><h2 id="_3-產品分類架構" tabindex="-1">3. 產品分類架構 <a class="header-anchor" href="#_3-產品分類架構" aria-label="Permalink to &quot;3. 產品分類架構&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>功率離散元件</span></span>
<span class="line"><span>├── MOSFET（功率電晶體）</span></span>
<span class="line"><span>│   ├── Low Voltage (&lt;100V) — 消費電子、DC/DC、NB</span></span>
<span class="line"><span>│   ├── Medium Voltage (100V-600V) — 伺服器電源、UPS</span></span>
<span class="line"><span>│   └── High Voltage (&gt;600V) — 車用動力、充電樁</span></span>
<span class="line"><span>├── IGBT（絕緣柵雙極電晶體）— 高壓大功率</span></span>
<span class="line"><span>├── SiC MOSFET（碳化矽功率電晶體）— 高壓+高頻</span></span>
<span class="line"><span>├── SiC SBD（蕭特基二極體）— 整流、續流</span></span>
<span class="line"><span>├── GaN HEMT（氮化鎵高電子遷移率電晶體）— 高頻充電</span></span>
<span class="line"><span>└── TVS/ESD（靜電保護元件）— 訊號保護</span></span></code></pre></div><hr><h2 id="_4-成長驅動因子" tabindex="-1">4. 成長驅動因子 <a class="header-anchor" href="#_4-成長驅動因子" aria-label="Permalink to &quot;4. 成長驅動因子&quot;">​</a></h2><h3 id="_1-ai-伺服器-gpu-功耗飆升-→-mosfet-用量暴增" tabindex="-1">① AI 伺服器：GPU 功耗飆升 → MOSFET 用量暴增 <a class="header-anchor" href="#_1-ai-伺服器-gpu-功耗飆升-→-mosfet-用量暴增" aria-label="Permalink to &quot;① AI 伺服器：GPU 功耗飆升 → MOSFET 用量暴增&quot;">​</a></h3><ul><li>GPU 單顆功耗從 300W 飆升至 700W-1200W+</li><li>每級電源轉換（AC→48V→1.8V/0.8V）需要低壓大電流 MOSFET</li><li>AI 伺服器（8xGPU）MOSFET 用量約 150-300 顆，是傳統伺服器的 3-5 倍</li><li>48V 供電架構取代 12V → MOSFET 從 30V 升級至 100V，單價提升</li><li><strong>強茂</strong>已切入 NVIDIA GB200 供應鏈，力拚 GB300 訂單（外資估 AI 營收佔比 9-12%）</li><li><strong>力智</strong>為 CPU/GPU/AI 加速器提供 SPS 電源管理方案，AI 營收佔比已突破 5%</li></ul><h3 id="_2-電動車-800v-平台-→-sic-滲透率提升" tabindex="-1">② 電動車 800V 平台 → SiC 滲透率提升 <a class="header-anchor" href="#_2-電動車-800v-平台-→-sic-滲透率提升" aria-label="Permalink to &quot;② 電動車 800V 平台 → SiC 滲透率提升&quot;">​</a></h3><ul><li>800V 電池架構推動 1200V SiC MOSFET 在牽引逆變器的大量採用</li><li>Tesla、BYD、Hyundai、Kia 等主流 EV 已標準化 SiC</li><li>汽車級 SiC 市場：2026 ~$82.4 億 → 2034 ~$319 億（CAGR 21.3%）</li><li>SiC 在 EV 中提供 5-8% 效率提升 → 更長續航、更快充電</li></ul><h3 id="_3-充電樁-儲能系統" tabindex="-1">③ 充電樁 + 儲能系統 <a class="header-anchor" href="#_3-充電樁-儲能系統" aria-label="Permalink to &quot;③ 充電樁 + 儲能系統&quot;">​</a></h3><ul><li>超快充（350kW+）需要 SiC/Si MOSFET 高效率轉換</li><li>儲能系統（BESS）大量使用 IGBT/MOSFET</li></ul><h3 id="_4-資料中心-48v-供電架構轉換" tabindex="-1">④ 資料中心 48V 供電架構轉換 <a class="header-anchor" href="#_4-資料中心-48v-供電架構轉換" aria-label="Permalink to &quot;④ 資料中心 48V 供電架構轉換&quot;">​</a></h3><ul><li>AI 伺服器推動從 12V 轉向 48V 供電架構</li><li>帶動中高壓 MOSFET（100V+）需求暴增</li></ul><h3 id="_5-家電-工業變頻化" tabindex="-1">⑤ 家電/工業變頻化 <a class="header-anchor" href="#_5-家電-工業變頻化" aria-label="Permalink to &quot;⑤ 家電/工業變頻化&quot;">​</a></h3><ul><li>變頻空調、洗衣機、工業馬達驅動持續推動 MOSFET/IGBT 需求</li></ul><hr><h2 id="_5-台廠全景圖-2026-年最新" tabindex="-1">5. 台廠全景圖（2026 年最新） <a class="header-anchor" href="#_5-台廠全景圖-2026-年最新" aria-label="Permalink to &quot;5. 台廠全景圖（2026 年最新）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">股票</th><th style="text-align:center;">代號</th><th style="text-align:left;">主要產品結構</th><th style="text-align:center;">2026 Q1 營收</th><th style="text-align:left;">2026 亮點與最新動態</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>強茂</strong></td><td style="text-align:center;">2481</td><td style="text-align:left;">二極體~40%, MOSFET~30%, TVS, SPS</td><td style="text-align:center;">4月12.97億(y+8.8%)</td><td style="text-align:left;">AI佔比9-12%,車用40%,交期30週,切入GB200</td></tr><tr><td style="text-align:left;"><strong>台半</strong></td><td style="text-align:center;">5425</td><td style="text-align:left;">MOS~10-15%, TVS, SiC驗證中</td><td style="text-align:center;">4月16.42億(創新高)</td><td style="text-align:left;">切入NVIDIA Rubin平台,SiC 1200V送樣,AI伺服器ODM驗證</td></tr><tr><td style="text-align:left;"><strong>力智</strong></td><td style="text-align:center;">6719</td><td style="text-align:left;">SPS, PMIC+MOS, Vcore</td><td style="text-align:center;">Q1營收9.8億</td><td style="text-align:left;">AI佔比&gt;5%,目標雙位數,GaN驅動IC出貨中</td></tr><tr><td style="text-align:left;"><strong>富鼎</strong></td><td style="text-align:center;">8261</td><td style="text-align:left;">High/Low V MOS, SPS</td><td style="text-align:center;">Q1營收7.82億(y+9.2%)</td><td style="text-align:left;">DC Fan業務+111%,高壓MOS需求強勁</td></tr><tr><td style="text-align:left;"><strong>尼克森</strong></td><td style="text-align:center;">3317</td><td style="text-align:left;">Low V MOS, IGBT</td><td style="text-align:center;">4月2.65億(y+10.8%)</td><td style="text-align:left;">前四月+y+12%,結構性成長中</td></tr><tr><td style="text-align:left;"><strong>杰力</strong></td><td style="text-align:center;">5299</td><td style="text-align:left;">Notebook MOS, 車用MOS研發中</td><td style="text-align:center;">Q1營收3.9億(q+29%)</td><td style="text-align:left;">車用認證中,新產品目標15-20%佔比</td></tr><tr><td style="text-align:left;"><strong>茂矽</strong></td><td style="text-align:center;">2342</td><td style="text-align:left;">MOS代工,SiC研發中</td><td style="text-align:center;">毛利率挑戰15-20%</td><td style="text-align:left;">SiC MOS+JBS 2026H2送樣,2027貢獻營收</td></tr><tr><td style="text-align:left;"><strong>力士</strong></td><td style="text-align:center;">4923</td><td style="text-align:left;">Low V MOS</td><td style="text-align:center;">—</td><td style="text-align:left;">轉虧為盈中,產品組合優化</td></tr></tbody></table><h3 id="台廠定位總結" tabindex="-1">台廠定位總結 <a class="header-anchor" href="#台廠定位總結" aria-label="Permalink to &quot;台廠定位總結&quot;">​</a></h3><ul><li><strong>強茂</strong>：台灣最大功率離散元件廠，全球二極體前十大，AI+車用雙主軸</li><li><strong>台半</strong>：中高壓 MOS 升級中，SiC 1200V 送樣驗證，切入 NVIDIA Rubin</li><li><strong>力智</strong>：台灣唯一高階 SPS 供應商，PMIC+MOS 整合先驅</li><li><strong>富鼎</strong>：高壓 MOS + SPS 雙引擎，DC Fan 業務爆發</li><li><strong>尼克森</strong>：穩定成長型，低壓 MOS 龍頭之一</li><li><strong>杰力</strong>：筆電 MOS 為主，積極轉型車用</li><li><strong>茂矽</strong>：晶圓代工模式（非 IDM），SiC 下半年送樣</li></ul><hr><h2 id="_6-全球競爭格局" tabindex="-1">6. 全球競爭格局 <a class="header-anchor" href="#_6-全球競爭格局" aria-label="Permalink to &quot;6. 全球競爭格局&quot;">​</a></h2><h3 id="idm-大廠-市場佔有率-50-55" tabindex="-1">IDM 大廠（市場佔有率 ~50-55%） <a class="header-anchor" href="#idm-大廠-市場佔有率-50-55" aria-label="Permalink to &quot;IDM 大廠（市場佔有率 ~50-55%）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">全球排名</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Infineon</strong></td><td style="text-align:center;">第1（~19.5%）</td><td style="text-align:left;">功率半導體全球龍頭，SiC/IGBT/MOSFET 全覆蓋</td></tr><tr><td style="text-align:left;"><strong>ON Semi</strong></td><td style="text-align:center;">第2-3</td><td style="text-align:left;">SiC 領導者之一，車用 MOSFET 強項</td></tr><tr><td style="text-align:left;"><strong>STMicroelectronics</strong></td><td style="text-align:center;">第3-4</td><td style="text-align:left;">N-Channel MOSFET 市佔 ~15%</td></tr><tr><td style="text-align:left;"><strong>Texas Instruments</strong></td><td style="text-align:center;">第4-5</td><td style="text-align:left;">低壓 MOSFET + PMIC 整合</td></tr><tr><td style="text-align:left;"><strong>Toshiba</strong></td><td style="text-align:center;">第6-7</td><td style="text-align:left;">IGBT + SiC 布局</td></tr></tbody></table><h3 id="sic-領導者" tabindex="-1">SiC 領導者 <a class="header-anchor" href="#sic-領導者" aria-label="Permalink to &quot;SiC 領導者&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:left;">定位</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Wolfspeed</strong></td><td style="text-align:left;">SiC 襯底全球龍頭，8 吋產能佈局中</td></tr><tr><td style="text-align:left;"><strong>ST</strong></td><td style="text-align:left;">SiC MOSFET + Module 量產</td></tr><tr><td style="text-align:left;"><strong>Infineon</strong></td><td style="text-align:left;">SiC Module 車用領先</td></tr><tr><td style="text-align:left;"><strong>Rohm</strong></td><td style="text-align:left;">SiC MOSFET 消費電子佈局</td></tr></tbody></table><h3 id="中國競爭者-大量擴產中" tabindex="-1">中國競爭者（大量擴產中） <a class="header-anchor" href="#中國競爭者-大量擴產中" aria-label="Permalink to &quot;中國競爭者（大量擴產中）&quot;">​</a></h3><ul><li><strong>天科合達</strong>：SiC 襯底中國龍頭</li><li><strong>三安光電</strong>：IDM 模式，SiC 全鏈佈局</li><li><strong>華潤微</strong>：MOSFET + IGBT 量產</li><li><strong>士蘭微</strong>：IGBT Module 中國領先</li></ul><hr><h2 id="_7-關鍵風險與機會" tabindex="-1">7. 關鍵風險與機會 <a class="header-anchor" href="#_7-關鍵風險與機會" aria-label="Permalink to &quot;7. 關鍵風險與機會&quot;">​</a></h2><h3 id="⚠️-風險" tabindex="-1">⚠️ 風險 <a class="header-anchor" href="#⚠️-風險" aria-label="Permalink to &quot;⚠️ 風險&quot;">​</a></h3><ol><li><strong>景氣循環</strong>：MOSFET 2022-2023 經歷嚴重庫存調整，週期性波動仍存</li><li><strong>SiC 良率</strong>：台廠 SiC 良率仍落後國際大廠（Wolfspeed、Infineon）</li><li><strong>中國追趕</strong>：SiC 6 吋產能大量開出，低價競爭壓力</li><li><strong>替代技術</strong>：GaN 在高頻充電領域蠶食 SiC/Si MOSFET</li><li><strong>關稅戰</strong>：地緣政治影響供應鏈布局</li></ol><h3 id="✅-機會" tabindex="-1">✅ 機會 <a class="header-anchor" href="#✅-機會" aria-label="Permalink to &quot;✅ 機會&quot;">​</a></h3><ol><li><strong>AI 伺服器爆發</strong>：MOSFET 用量 3-5 倍增長，SPS 整合提高單價</li><li><strong>800V EV 平台普及</strong>：SiC 滲透率從低個位數朝雙位數邁進</li><li><strong>結構性缺貨</strong>：2026 年 MOSFET 交期拉長至 25-37 週（Diodes、Vishay、Onsemi）</li><li><strong>中國轉單效應</strong>：安世半導體（中資 Nexperia）客戶轉向台廠</li><li><strong>8 吋 SiC 轉換</strong>：率先完成 8 吋量產者將獲得車用供應鏈門票</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>DataMintelligence</strong> (2026-05): 全球功率半導體市場 ~$557億, SiC CAGR 24.68%</li><li><strong>IMARC Group</strong> (2026-05): 功率半導體市場 ~$58.8億, CAGR 3.0-5.8%</li><li><strong>GM Insights</strong> (2026-05): 功率半導體市場, Infineon 市佔 ~19.5%</li><li><strong>Mordor Intelligence</strong> (2026-05): SiC 功率半導體市場 ~$34億, CAGR 27.9%</li><li><strong>Fortune Business Insights</strong> (2026-05): 汽車級 SiC ~$82.4億→$319億, CAGR 21.3%</li><li><strong>GII (Global Insights)</strong> (2026-05): Power MOSFET ~$98.1億, CAGR 6.3%</li><li><strong>Investing.com / Baird</strong> (2026-05): MOSFET 交期 25-37 週, SiC 汽車級 &gt;52 週</li><li><strong>工商時報</strong> (2026-03): 強茂法說會, AI 佔比 9-12%, 交期 30 週</li><li><strong>鉅亨網</strong> (2026-05): 台半 4月營收創新高, 切入 NVIDIA Rubin</li><li><strong>CMoney</strong> (2026-05): 力智 AI 佔比&gt;5%, 富鼎 DC Fan +111%</li><li><strong>Vocus / 經濟日報</strong> (2026-05): 富鼎、茂矽、尼克森、杰力法說會摘要</li><li><strong>TechNews</strong> (2026-05): 尼克森 4月營收 y+10.8%</li></ol>`,53)])])}const f=e(i,[["render",s]]);export{y as __pageData,f as default};
